cordId: null,\r\n            titleDialog: \"Stock de producto\",\r\n            series: null,\r\n            loading: false\r\n        };\r\n    },\r\n    created() {\r\n        this.$eventHub.$on(\"reloadData\", () => {\r\n            this.close();\r\n        });\r\n        //console.log(this.typeUser)\r\n    },\r\n    methods: {\r\n        clickStock(record) {\r\n            this.recordId = record.id;\r\n            this.showDialogStock = true;\r\n        },\r\n        open() {\r\n            this.total = this.warehouses.reduce(\r\n                (a, b) => a + Number(b.stock),\r\n                0\r\n            );\r\n\r\n            if (this.item.max_quantity) {\r\n                this.total = this.total / this.item.max_quantity;\r\n            }\r\n\r\n            if (this.hasSerie) {\r\n                this.getSeries();\r\n            }\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n        async getSeries() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/documents/get-series/${this.itemId}`\r\n                );\r\n                this.series = response.data;\r\n            } catch (e) {\r\n                console.log(e);\r\n                const {\r\n                    response: {\r\n                        data: { message }\r\n                    }\r\n                } = e;\r\n                this.$toast.error(message);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// resources/js/views/items/partials/warehouses.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      directives: [\n        {\n          name: \"loading\",\n          rawName: \"v-loading\",\n          value: _vm.loading,\n     