"fa fa-plus\"\r\n                                        aria-hidden=\"true\"\r\n                                    ></i>\r\n                                    Agregar\r\n                                </el-button>\r\n                            </div>\r\n                        </div>\r\n                        <div\r\n                            class=\"row\"\r\n                            style=\"margin-top:25px;\"\r\n                            v-if=\"details != 0\"\r\n                        >\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>DESCP.</th>\r\n                                        <th>CANT.</th>\r\n                                        <th>PRECIO UNIT</th>\r\n                                        <th>PRECIO ADICIONAL</th>\r\n                                        <th>PRECIO TOTAL</th>\r\n                                        <th>ELIMINAR</th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr v-for=\"(dt, idx) in details\" :key=\"idx\">\r\n                                        <td>{{ dt.item.detail }}</td>\r\n                                        <td>\r\n                                            {{ dt.quantity }}\r\n                                            {{ dt.item.unit_id }}\r\n                                        </td>\r\n                                        <td>{{ dt.price }}</td>\r\n                                        <td>{{ dt.extra_price }}</td>\r\n                                        <td>\r\n                                            {{\r\n                                                dt.price * dt.quantity +\r\n                                                    dt.extra_price\r\n                                            }}\r\n                                        </td>\r\n                                        <td>\r\n                                            <el-button\r\n                                                type=\"danger\"\r\n                                                size=\"mini\"\r\n                                                @click=\"\r\n                                                    deleteDetail(\r\n                                                        dt.item_detail_id\r\n                                                    )\r\n                                                \"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fa fa-trash\"\r\n                                                    aria-hidden=\"true\"\r\n                                                ></i>\r\n                                            </el-button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n                        </div>\r\n                    </template>\r\n                    <div class=\"col-md-12 p-2\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.description }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Detalle - Concepto</label\r\n                            >\r\n                            <el-input\r\n                                type=\"textarea\"\r\n                                v-model=\"form.description\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.description\"\r\n                                v-text=\"errors.description[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n        <el-dialog\r\n            v-loading=\"loading\"\r\n            width=\"50%\"\r\n            append-to-body\r\n            :visible.sync=\"showCreateItem\"\r\n        >\r\n            <div class=\"row p-2\">\r\n                <div class=\"col-md-8\">\r\n                    <label for=\"product\">\r\n                        Descripción\r\n                    </label>\r\n                    <el-input v-model=\"newItem.item\"></el-input>\r\n                </div>\r\n                <div class=\"col-md-4\">\r\n                    <label for=\"type\">\r\n                        Unidad de medida\r\n                    </label>\r\n                    <el-select v-model=\"newItem.unitTypeId\">\r\n                        <el-option\r\n                            v-for=\"(type, idx) in unitTypes\"\r\n                            :key=\"idx\"\r\n                            :value=\"type.id\"\r\n                            :label=\"type.description\"\r\n                        ></el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-12 text-right \" style=\"margin-top:15px;\">\r\n                    <el-button type=\"primary\" @click=\"saveUnitType\"\r\n                        >Guardar</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n        </el-dialog>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n//import { EventBus } from \"../../../helpers/bus\";\r\n\r\nexport default {\r\n    props: [\"cashid\", \"showDialog\", \"activeName\", \"items_detail\", \"unitTypes\"],\r\n    data() {\r\n        return {\r\n            hasDetails: false,\r\n            newItem: {},\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"restaurant/worker/expenses\",\r\n            errors: {},\r\n            errors_group: {},\r\n            errors_category: {},\r\n            errors_subcategory: {},\r\n            form: {},\r\n            array_subcategorias: [],\r\n            array_categorias: [],\r\n            details: [],\r\n            detail: {\r\n                extra_price: 0\r\n            },\r\n            array_group: [],\r\n            register_group: false,\r\n            register_category: false,\r\n            register_subcategory: false,\r\n            form_group: [],\r\n            form_category: [],\r\n            form_subcategory: [],\r\n            array_company: [],\r\n            payment_methods: [],\r\n            showCreateItem: false\r\n        };\r\n    },\r\n    watch: {},\r\n    created() {\r\n        this.initForm();\r\n        this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.array_group = response.data.gruop;\r\n            this.array_categorias = response.data.category;\r\n            this.array_subcategorias = response.data.subcategory;\r\n            this.array_company = response.data.company;\r\n            this.payment_methods = response.data.methods;\r\n            this.form.method = this.payment_methods[0].description;\r\n            this.form.soap_type_id = this.array_company.soap_type_id;\r\n        });\r\n    },\r\n    methods: {\r\n        async saveUnitType() {\r\n            if (!this.newItem.item || !this.newItem.unitTypeId) {\r\n                return this.$toast.error(\"Verifique los datos\");\r\n            }\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http.post(\"../save_item\", {\r\n                    description: this.newItem.item,\r\n                    unitTypeId: this.newItem.unitTypeId\r\n                });\r\n                const {\r\n                    data: { item, success, message }\r\n                } = response;\r\n                success\r\n                    ? this.$toast.success(message)\r\n                    : this.$toast.error(message);\r\n                if (success) {\r\n                    this.$emit(\"update:items_detail\", [item]);\r\n                    this.detail.item_detail_id = item.id;\r\n                    this.showCreateItem = false;\r\n                    this.newItem = {};\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        openCreateItem() {\r\n            this.showCreateItem = true;\r\n        },\r\n        deleteDetail(id) {\r\n            this.details = this.details.filter(f => f.item_detail_id != id);\r\n            let total = this.details.reduce(\r\n                (a, b) => a + (b.price * b.quantity + b.extra_price),\r\n                0\r\n            );\r\n            this.form.amount = total;\r\n            this.hasDetails = this.details.length != 0;\r\n        },\r\n        addDetail() {\r\n            let { price, quantity, item_detail_id } = this.detail;\r\n\r\n            if (!price || !quantity || !item_detail_id) {\r\n                this.$toast.error(\"Verifique los datos\");\r\n                return;\r\n            }\r\n            let item = this.items_detail.find(\r\n                i => i.id == this.detail.item_detail_id\r\n            );\r\n\r\n            let detailExist = this.details.find(\r\n                d => d.item_detail_id == item_detail_id\r\n            );\r\n\r\n            if (detailExist) {\r\n                detailExist.quantity += quantity;\r\n                detailExist.price = price;\r\n\r\n                this.details = [\r\n                    ...this.details.filter(\r\n                        d => d.item_detail_id != item_detail_id\r\n                    ),\r\n                    detailExist\r\n                ];\r\n            } else {\r\n                this.details = [\r\n                    ...this.details,\r\n                    {\r\n                        ...this.detail,\r\n                        item\r\n                    }\r\n                ];\r\n            }\r\n\r\n            this.hasDetails = this.details.length != 0;\r\n\r\n            this.detail = {};\r\n            this.detail.extra_price = 0;\r\n            let total = this.details.reduce(\r\n                (a, b) => a + (b.price * b.quantity + b.extra_price),\r\n                0\r\n            );\r\n\r\n            this.form.amount = total;\r\n        },\r\n        searchRemoteItems(input) {\r\n            if (input.length > 1 && this.form.item_add == false) {\r\n                this.$emit(\"getItemsDetail\", input);\r\n            }\r\n        },\r\n        loadDataUtilities() {},\r\n        initGroup() {\r\n            this.form_group = {\r\n                id: null,\r\n                group: null,\r\n                type: 2\r\n            };\r\n        },\r\n        initCategory() {\r\n            this.form_category = {\r\n                id: null,\r\n                category: null,\r\n                type: 2\r\n            };\r\n        },\r\n        initSubcategory() {\r\n            this.form_subcategory = {\r\n                id: null,\r\n                subcategory: null,\r\n                type: 2\r\n            };\r\n        },\r\n        initForm() {\r\n            this.details = [];\r\n            this.errors = {};\r\n            this.detail = {};\r\n            this.form = {\r\n                id: null,\r\n                user_id: this.userid,\r\n                seller_id: null,\r\n                method: null,\r\n                group_id: 1,\r\n                category_id: 1,\r\n                subcategory_id: 1,\r\n                item_add: false,\r\n                amount: 0.0,\r\n                date: moment().format(\"YYYY-MM-DD\"),\r\n                description: null,\r\n                extra_price: 0.0,\r\n                close: null,\r\n                type: this.activeName == \"expenses\" ? 2 : 1,\r\n                state: 1,\r\n                soap_type_id: \"01\",\r\n                incomes: this.activeName == \"incomes\",\r\n                expenses: this.activeName == \"expenses\"\r\n            };\r\n\r\n            this.initGroup();\r\n            this.initCategory();\r\n            this.initSubcategory();\r\n        },\r\n        submit_group() {\r\n            this.$http\r\n                .post(`/groups`, this.form_group)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.register_group = false;\r\n                        this.array_group.push({\r\n                            id: response.data.data.id,\r\n                            group: response.data.data.group,\r\n                            type: 2\r\n                        });\r\n                        this.form.group_id = response.data.data.id;\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors_group = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        submit_Category() {\r\n            this.$http\r\n                .post(`/restaurant/worker/category`, this.form_category)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.register_category = false;\r\n                        this.array_categorias.push({\r\n                            id: response.data.data.id,\r\n                            category: response.data.data.category,\r\n                            type: 2\r\n                        });\r\n                        this.form.category_id = response.data.data.id;\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors_category = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        submit_Subcategory() {\r\n            this.$http\r\n                .post(`/restaurant/worker/subcategories`, this.form_subcategory)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.register_subcategory = false;\r\n                        this.array_subcategorias.push({\r\n                            id: response.data.data.id,\r\n                            subcategory: response.data.data.subcategory,\r\n                            type: 2\r\n                        });\r\n                        this.form.subcategory_id = response.data.data.id;\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors_subcategory = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        create() {\r\n            this.initForm();\r\n            this.titleDialog =\r\n                this.activeName == \"expenses\"\r\n                    ? \"Nuevo Egreso Caja\"\r\n                    : \"Nuevo Ingreso Caja\";\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                    });\r\n            } else {\r\n                this.form.method = this.payment_methods[0].description;\r\n            }\r\n            this.detail.extra_price = 0.0;\r\n            this.hasDetails = this.details.length != 0;\r\n        },\r\n        submit() {\r\n            let total = this.details.reduce(\r\n                (a, b) => a + (b.price * b.quantity + b.extra_price),\r\n                0\r\n            );\r\n            if (total > this.form.amount) {\r\n                return this.$toast.error(\r\n                    \"La suma de los items no puede ser mayor al gasto general\"\r\n                );\r\n            }\r\n            this.form.cashid = this.cashid;\r\n            this.form.items = this.details;\r\n            this.loading_submit = true;\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        this.$emit(\"getRecords\");\r\n                        this.details = [];\r\n                        this.detail = {};\r\n                        this.close();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data.errors;\r\n                    } else {\r\n                        this.$toast.error(error.response.data.message);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/expenses_incomes_form.vue","var render = function() {\n  var _vm = this\n  var _h = _vm.$createElement\n  var _c = _vm._self._c || _h\n  return _c(\n    \"el-dialog\",\n    {\n      directives: [\n        {\n          name: \"loading\",\n          rawName: \"v-loading\",\n          value: _vm.loading,\n          expression: \"loading\"\n        }\n      ],\n      attrs: {\n        title: _vm.titleDialog,\n        visible: _vm.showDialog,\n        \"append-to-body\": \"\",\n        width: \"50%\"\n      },\n      on: { close: _vm.close, open: _vm.create }\n    },\n    [\n      _c(\n        \"form\",\n        {\n          attrs: { autocomplete: \"off\" },\n          on: {\n            submit: function($event) {\n              $event.preventDefault()\n              return _vm.submit.apply(null, arguments)\n            }\n          }\n        },\n        [\n          _c(\"div\", { staticClass: \"form-body\" },